        // 100 = 2 * 2 * 5 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(100);
        int[] expected = {2, 2, 5, 5};
        assertArrayEquals(expected, actual);
    }

    // ==================== Large Numbers ====================

    @Test
    void testFactorizeLarge() {
        // Test with large factorizer
        int[] actual = largeFactorizer.computePrimeFactorization(1000000);
        // 1000000 = 2^6 * 5^6 = 2 * 2 * 2 * 2 * 2 * 2 * 5 * 5 * 5 * 5 * 5 * 5
        int[] expected = {2, 2, 2, 2, 2, 2, 5, 5, 5, 5, 5, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize12345() {
        // 12345 = 3 * 5 * 823
        int[] actual = largeFactorizer.computePrimeFactorization(12345);
        int[] expected = {3, 5, 823};
        assertArrayEquals(expected, actual);
    }

    // ==================== More Edge Cases ====================

    @Test
    void testFactorize15() {
        // 15 = 3 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(15);
        int[] expected = {3, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize25() {
        // 25 = 5 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(25);
        int[] expected = {5, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize49() {
        // 49 = 7 * 7
        int[] actual = smallFactorizer.computePrimeFactorization(49);
        int[] expected = {7, 7};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize72() {
        // 72 = 2 * 2 * 2 * 3 * 3
        int[] actual = smallFactorizer.computePrimeFactorization(72);
        int[] expected = {2, 2, 2, 3, 3};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorize90() {
        // 90 = 2 * 3 * 3 * 5
        int[] actual = smallFactorizer.computePrimeFactorization(90);
        int[] expected = {2, 3, 3, 5};
        assertArrayEquals(expected, actual);
    }

    @Test
    void testFactorizeLargeAtMax() {
        // Test at the boundary of large factorizer's max
        int[] actual = largeFactorizer.computePrimeFactorization(49999999);
        // This should factorize correctly regardless of what the factors are
        assertArrayEquals(factorizeNaive(49999999), actual);
    }

    // Helper method to verify factorization
    private int[] factorizeNaive(int n) {
        java.util.List<Integer> factors = new java.util.ArrayList<>();
        int remaining = n;

        for (int i = 2; i * i <= remaining; i++) {
            while (remaining % i == 0) {
                factors.add(i);
                remaining /= i;
            }
        }

        if (remaining > 1) {
            factors.add(remaining);
        }

        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }
        return result;
    }
}

package main.rice;

import java.util.ArrayList;
import java.util.List;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {

    private List<Integer> primes;
    private int maxNumToFactorize;

    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNumToFactorize = maxNumToFactorize;
        this.primes = sieveOfEratosthenes(maxNumToFactorize);
    }

    /**
     * Computes the prime factorization of the given number.
     * Returns an array of prime factors in ascending order, including repeats.
     * Returns null for invalid inputs (negative, 0, 1, or exceeding maxNumToFactorize).
     */
    public int[] computePrimeFactorization(int numToFactorize) {
        // Edge cases: negative, 0, or 1 should return null
        if (numToFactorize <= 1) {
            return null;
        }

        // Numbers exceeding maxNumToFactorize should return null
        if (numToFactorize > maxNumToFactorize) {
            return null;
        }

        List<Integer> factors = new ArrayList<>();
        int remaining = numToFactorize;

        // Try each prime in the precomputed list
        for (int prime : primes) {
            // If prime squared is greater than remaining, any remaining value is prime itself
            if (prime * prime > remaining) {
                break;
            }

            // Divide out this prime as many times as possible
            while (remaining % prime == 0) {
                factors.add(prime);
                remaining /= prime;
            }
        }

        // If remaining > 1, it is a prime factor
        if (remaining > 1) {
            factors.add(remaining);
        }

        // Convert list to array
        int[] result = new int[factors.size()];
        for (int i = 0; i < factors.size(); i++) {
            result[i] = factors.get(i);
        }

        return result;
    }

    /**
     * Generates all prime numbers up to n using the Sieve of Eratosthenes algorithm.
     */
    private List<Integer> sieveOfEratosthenes(int n) {
        List<Integer> primes = new ArrayList<>();

        if (n < 2) {
            return primes;
        }

        boolean[] isPrime = new boolean[n + 1];
        for (int i = 2; i <= n; i++) {
            isPrime[i] = true;
        }

        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }

        for (int i = 2; i <= n; i++) {
            if (isPrime[i]) {
                primes.add(i);
            }
        }

        return primes;
    }
}

